  {id:"v2u11l9",title:"De Directeur & Het Team",icon:"👔",xp:15,board:true,steps:[
        {type:"intro",title:"De Directeur & Het Team",desc:"Workplace hierarchy and team vocabulary. Essential for discussing your job, colleagues, and management in Dutch.",goals:["de directeur: director / manager","het team: team","gevaarlijk: dangerous","begrijpelijk: understandable","Use them in professional contexts"]},
        {type:"teach",trg:"de directeur",src:"the director / manager",pos:"noun",gender:"c",phonetic:"duh dee-REK-tur",note:"De-word. Plural: directeuren.\nThe person at the top of an organisation.\n'Algemeen directeur' = CEO (general director).",example:"A: De directeur is vandaag niet op kantoor.\nB: Wanneer is hij terug?\nA: Morgen, hopelijk.",exampleSrc:"A: The director is not in the office today.\nB: When is he back?\nA: Tomorrow, hopefully.",funFact:"Cognate with English 'director', French 'directeur'. From Latin 'dirigere' (to direct, to guide)."},
        {type:"teach",trg:"het team",src:"the team",pos:"noun",gender:"n",phonetic:"hut teem",note:"Het-word. Plural: teams.\nUsed both for sports teams and work teams.\n'Het team werkt samen.' = The team works together.",example:"A: Ons team werkt goed samen.\nB: Dat klinkt geweldig!\nA: Ja, de directeur is blij.",exampleSrc:"A: Our team works well together.\nB: That sounds great!\nA: Yes, the director is happy.",funFact:"Borrowed from English 'team'. Now fully integrated into Dutch. Even the plural is 'teams' (not 'temen')."},
        {type:"teach",trg:"gevaarlijk",src:"dangerous",pos:"adj",gender:null,phonetic:"guh-VAH-ruh-luk",note:"Three syllables: ge-VAAR-lijk.\n'Gevaar' = danger. The suffix '-lijk' makes it an adjective.\n'Dat is gevaarlijk!' = That's dangerous!",example:"A: Wees voorzichtig. De situatie is gevaarlijk.\nB: Ik begrijp het.\nA: Bel me als er iets is.",exampleSrc:"A: Be careful. The situation is dangerous.\nB: I understand.\nA: Call me if anything happens.",funFact:"From 'gevaar' (danger) + '-lijk' (adjective suffix). The '-lijk' suffix is similar to English '-like' or '-ly'."},
        {type:"teach",trg:"begrijpelijk",src:"understandable / comprehensible",pos:"adj",gender:null,phonetic:"buh-GRAYP-uh-luk",note:"From 'begrijpen' (to understand) + '-lijk'.\n'Dat is begrijpelijk.' = That's understandable.\nUsed to show empathy and acknowledgement.",example:"A: Ik ben moe na zo'n lange vergadering.\nB: Dat is heel begrijpelijk!\nA: Dank je.",exampleSrc:"A: I am tired after such a long meeting.\nB: That is very understandable!\nA: Thanks.",funFact:"From 'begrijpen' (to understand) + '-lijk'. Dutch builds adjectives from verbs this way: stem + lijk = able to be done."},
        {type:"tip",title:"🧩 The -lijk Suffix",text:"The suffix '-lijk' turns nouns and verbs into adjectives:\n\ngevaar (danger) + lijk = gevaarlijk (dangerous)\nbegrijpen (to understand) + elijk = begrijpelijk\nvriend (friend) + elijk = vriendelijk (friendly)\nmogelijk = possible (mogen + elijk)\n\nRecognizing '-lijk' unlocks hundreds of adjectives for free!"},
        {type:"mc",q:"'De situatie is gevaarlijk.' means:",opts:["The situation is dangerous","The situation is unclear","The situation is easy","The situation is pleasant"],ans:"The situation is dangerous",hint:"Gevaarlijk comes from 'gevaar' which means..."},
        {type:"mc",q:"'Dat is begrijpelijk.' is used when:",opts:["Something is confusing","Something makes sense and you show empathy","You disagree strongly","Something is very funny"],ans:"Something makes sense and you show empathy",hint:"Begrijpen = to understand"},
        {type:"fb",opts:["directeur","team","collega","baas"],hint:"The person at the top of the organisation",s:"De ___ heeft een vergadering met het team.",a:"directeur"},
        {type:"match",pairs:[{trg:"de directeur",src:"the director/manager"},{trg:"het team",src:"the team"},{trg:"gevaarlijk",src:"dangerous"},{trg:"begrijpelijk",src:"understandable"}]},
        {type:"fb",opts:["gevaarlijk","begrijpelijk","geweldig","aardig"],hint:"Something you should NOT do because of risk",s:"Zonder helm fietsen is ___.",a:"gevaarlijk"}
  ]}
